	// ------------------------------
	// OVERLOAD: VIEW OR EDIT RECORD
	// ------------------------------
	public ModelAndView getViewOrEditPage(String acctNo, String formMode) {
		ModelAndView mv = new ModelAndView("BRRS/M_CALOC");

		if (acctNo != null) {
			M_CALOC_Detail_Entity caloc = findDetailByAcctNumber(acctNo);
			if (caloc != null && caloc.getReportDate() != null) {
				String formattedDate = new SimpleDateFormat("dd/MM/yyyy").format(caloc.getReportDate());
				mv.addObject("asondate", formattedDate);
			}
			mv.addObject("MCALOCData", caloc);
		}

		mv.addObject("displaymode", "edit");
		mv.addObject("formmode", formMode != null ? formMode : "edit");
		return mv;
	}

	@Transactional
	// ------------------------------
	// OVERLOAD: UPDATE SINGLE DETAIL RECORD
	// ------------------------------
	public ResponseEntity<?> updateDetailEdit1(HttpServletRequest request) {
		try {
			String acctNo = request.getParameter("acctNumber");
			String acctBalanceInpula = request.getParameter("balEquiToBwp");
			String acctName = request.getParameter("acctName");
			String reportDateStr = request.getParameter("reportDate"); // yyyy-MM-dd from HTML

			logger.info("Received update for ACCT_NO: {}", acctNo);

			M_CALOC_Detail_Entity existing = findDetailByAcctNumber(acctNo);

			if (existing == null) {
				logger.warn("No record found for ACCT_NO: {}", acctNo);
				return ResponseEntity.status(HttpStatus.NOT_FOUND).body("Record not found for update.");
			}

			boolean isChanged = false;

			// Update account name
			if (acctName != null && !acctName.isEmpty() && !acctName.equals(existing.getAcctName())) {

				existing.setAcctName(acctName);
				isChanged = true;
				logger.info("Updated acctName → {}", acctName);
			}

			// Update Pula balance
			if (acctBalanceInpula != null && !acctBalanceInpula.isEmpty()) {

				BigDecimal newBalance = new BigDecimal(acctBalanceInpula.replace(",", ""));

				if (existing.getBalEquiToBwp() == null || existing.getBalEquiToBwp().compareTo(newBalance) != 0) {

					existing.setBalEquiToBwp(newBalance);
					isChanged = true;
					logger.info("Updated acctBalanceInPula → {}", newBalance);
				}
			}

			if (!isChanged) {
				logger.info("No changes detected for ACCT_NO {}", acctNo);
				return ResponseEntity.ok("No changes were made.");
			}

			// Save updated data
			saveDetailEntity(existing);

			logger.info("Record updated successfully for ACCT_NO {}", acctNo);

			// Format date "yyyy-MM-dd" → "dd-MM-yyyy"
			String formattedDate = new SimpleDateFormat("dd-MM-yyyy")
					.format(new SimpleDateFormat("yyyy-MM-dd").parse(reportDateStr));

			// Register after-commit callback
			TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
				@Override
				public void afterCommit() {
					try {
						logger.info("AFTER COMMIT → Executing BRRS_M_CALOC_SUMMARY_PROCEDURE({})", formattedDate);

						jdbcTemplate.update("BEGIN BRRS_M_CALOC_SUMMARY_PROCEDURE(?); END;", formattedDate);

					} catch (Exception e) {
						logger.error("Error executing after-commit procedure", e);
					}
				}
			});

			return ResponseEntity.ok("Record updated successfully!");

		} catch (Exception e) {
			logger.error("Error updating CALOC record", e);
			return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
					.body("Error updating record: " + e.getMessage());
		}
	}

	// ------------------------------
	// GET RESUBMISSION DATA
	// ------------------------------
	public List<Object[]> getM_CALOCResub() {
		List<Object[]> resubList = new ArrayList<>();
		try {
			List<M_CALOC_Archival_Summary_Entity1> latestArchivalList = getArchivalSummary1WithVersion();

			if (latestArchivalList != null && !latestArchivalList.isEmpty()) {
				for (M_CALOC_Archival_Summary_Entity1 entity : latestArchivalList) {
					resubList.add(new Object[] { entity.getReportDate(), entity.getReportVersion(),
							entity.getReportResubDate() });
				}
				System.out.println("Fetched " + resubList.size() + " record(s)");
			} else {
				System.out.println("No archival data found.");
			}

		} catch (Exception e) {
			System.err.println("Error fetching M_CALOC Resub data: " + e.getMessage());
			e.printStackTrace();
		}
		return resubList;
	}

	// Archival View
	// ------------------------------
	// GET ARCHIVAL LIST DATA
	// ------------------------------
	public List<Object[]> getM_CALOCArchival() {
		List<Object[]> archivalList = new ArrayList<>();

		try {
			List<M_CALOC_Archival_Summary_Entity1> repoData = getArchivalSummary1WithVersion();

			if (repoData != null && !repoData.isEmpty()) {
				for (M_CALOC_Archival_Summary_Entity1 entity : repoData) {
					Object[] row = new Object[] { entity.getReportDate(), entity.getReportVersion(),
							entity.getReportResubDate() };
					archivalList.add(row);
				}

				System.out.println("Fetched " + archivalList.size() + " archival records");
				M_CALOC_Archival_Summary_Entity1 first = repoData.get(0);
				System.out.println("Latest archival version: " + first.getReportVersion());
			} else {
				System.out.println("No archival data found.");
			}

		} catch (Exception e) {
			System.err.println("Error fetching M_CALOC Archival data: " + e.getMessage());
			e.printStackTrace();
		}

		return archivalList;
	}

// Normal Email Excel
	// ------------------------------
	// GENERATE EMAIL EXCEL REPORT
	// ------------------------------
	private byte[] BRRS_M_CALOCEmailExcel(String filename, String reportId, String fromdate, String todate,
			String currency, String dtltype, String type, BigDecimal version) throws Exception {

		logger.info("Service: Starting Email Excel generation process in memory.");

		// ARCHIVAL check
		if ("ARCHIVAL".equalsIgnoreCase(type) && version != null) {
			try {
				return BRRS_M_CALOCEmailArchivalExcel(filename, reportId, fromdate, todate, currency, dtltype, type,
						version);
			} catch (ParseException e) {
				logger.error("Invalid report date format: {}", fromdate, e);
				throw new RuntimeException("Date format must be dd-MMM-yyyy (e.g. 31-Jul-2025)");
			}
		}

		// -------------------------
		// FETCH DATA
		// -------------------------
		List<M_CALOC_Summary_Entity1> dataList1 = getSummary1ByDate(dateformat.parse(todate));

		List<M_CALOC_Summary_Entity2> dataList2 = getSummary2ByDate(dateformat.parse(todate));

		List<M_CALOC_Summary_Entity3> dataList3 = getSummary3ByDate(dateformat.parse(todate));

		if (dataList1.isEmpty() && dataList2.isEmpty() && dataList3.isEmpty()) {
			logger.warn("Service: No data found for BRRSM_CALOC report.");
			return new byte[0];
		}

		// -------------------------
		// TEMPLATE LOAD
		// -------------------------
		String templateDir = env.getProperty("output.exportpathtemp");
		Path templatePath = Paths.get(templateDir, filename);

		logger.info("Loading template from: {}", templatePath.toAbsolutePath());

		if (!Files.exists(templatePath)) {
			throw new FileNotFoundException("Template file not found: " + templatePath.toAbsolutePath());
		}

		if (!Files.isReadable(templatePath)) {
			throw new SecurityException("Template file not readable: " + templatePath.toAbsolutePath());
		}

		try (InputStream templateInputStream = Files.newInputStream(templatePath);
				Workbook workbook = WorkbookFactory.create(templateInputStream);
				ByteArrayOutputStream out = new ByteArrayOutputStream()) {

			Sheet sheet = workbook.getSheetAt(0);
			CreationHelper createHelper = workbook.getCreationHelper();
			// -------------------------
			// STYLE DEFINITIONS
			// -------------------------
			CellStyle textStyle = workbook.createCellStyle();
			textStyle.setBorderBottom(BorderStyle.THIN);
			textStyle.setBorderTop(BorderStyle.THIN);
			textStyle.setBorderLeft(BorderStyle.THIN);
			textStyle.setBorderRight(BorderStyle.THIN);

			Font font = workbook.createFont();
			font.setFontHeightInPoints((short) 8);
			font.setFontName("Arial");

			CellStyle numberStyle = workbook.createCellStyle();
			numberStyle.cloneStyleFrom(textStyle);
			numberStyle.setFont(font);
			// DATE STYLE
			CellStyle dateStyle = workbook.createCellStyle();
			dateStyle.cloneStyleFrom(textStyle);

			dateStyle.setDataFormat(createHelper.createDataFormat().getFormat("dd-MM-yyyy"));

			dateStyle.setFont(font);

			// Populate Data
			if (!dataList1.isEmpty()) {
				populateEntity1EmailData(sheet, dataList1.get(0), textStyle, numberStyle, dateStyle);
			}

			// -------------------------
			// POPULATE DATA
			// -------------------------
			if (!dataList1.isEmpty()) {
				populateEntity1EmailData(sheet, dataList1.get(0), textStyle, numberStyle, dateStyle);
			}

			if (!dataList2.isEmpty()) {
				populateEntity2EmailData(sheet, dataList2.get(0), textStyle, numberStyle);
			}

			if (!dataList3.isEmpty()) {
				populateEntity3EmailData(sheet, dataList3.get(0), textStyle, numberStyle);
			}

			workbook.setForceFormulaRecalculation(true);
			workbook.write(out);

			logger.info("Email Excel generated successfully ({} bytes).", out.size());
			ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
			if (attrs != null) {
				HttpServletRequest request = attrs.getRequest();
				String userid = (String) request.getSession().getAttribute("USERID");
				auditService.createBusinessAudit(userid, "DOWNLOAD", "M_CALOC EMAIL SUMMARY", null,
						"M_CALOC_SUMMARYTABLE");
			}
			return out.toByteArray();
		}
	}

