	// ------------------------------
	// JDBC: FIND DETAIL BY ACCOUNT NUMBER
	// ------------------------------
	private M_CALOC_Detail_Entity findDetailByAcctNumber(String acctNo) {
		String sql = "SELECT * FROM BRRS_M_CALOC_DETAILTABLE WHERE ACCT_NUMBER = ?";
		List<M_CALOC_Detail_Entity> list = jdbcTemplate.query(sql, new Object[] { acctNo },
				new org.springframework.jdbc.core.BeanPropertyRowMapper<>(M_CALOC_Detail_Entity.class));
		return list.isEmpty() ? null : list.get(0);
	}

	// ------------------------------
	// JDBC: UPDATE DETAIL BY ACCOUNT NUMBER
	// ------------------------------
	private void saveDetailEntity(M_CALOC_Detail_Entity entity) {
		String sql = "UPDATE BRRS_M_CALOC_DETAILTABLE SET ACCT_NAME = ?, BAL_EQUI_TO_BWP = ? WHERE ACCT_NUMBER = ?";
		jdbcTemplate.update(sql, entity.getAcctName(), entity.getBalEquiToBwp(), entity.getAcctNumber());
	}

