	private List<M_CALOC_Archival_Summary_Entity1> getArchivalSummary1WithVersion() {
		String sql = "SELECT * FROM BRRS_M_CALOC_ARCHIVALTABLE_SUMMARY1 WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION ASC";
		return jdbcTemplate.query(sql,
				new org.springframework.jdbc.core.BeanPropertyRowMapper<>(M_CALOC_Archival_Summary_Entity1.class));
	}

